import React, { Fragment, useState, useEffect } from "react";
import { getAllUser, getAllCategory, getAllProduct, getOrders } from "../shop/auth/fetchApi";
import AdminLayout from "../admin/layout";

const Panel = ({ title, children }) => (
  <div className="bg-white shadow p-4 rounded">
    <div className="font-semibold mb-2">{title}</div>
    {children}
  </div>
);

const SuperAdminDashboard = () => {
  const [allUsers, setAllUsers] = useState(null);
  const [allCategories, setAllCategories] = useState(null);
  const [allProducts, setAllProducts] = useState(null);
  const [allOrders, setAllOrders] = useState(null);

  const fetchData = async () => {
    let responseData = await getAllUser();
    if (responseData.Users) {
      setAllUsers(responseData.Users);
    }
    responseData = await getAllCategory();
    if (responseData.Categories) {
      setAllCategories(responseData.Categories);
    }
    responseData = await getAllProduct();
    if (responseData.Products) {
      setAllProducts(responseData.Products);
    }
    responseData = await getOrders();
    if (responseData.Orders) {
      setAllOrders(responseData.Orders);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);
  const Details = (
    <div className="space-y-1 text-sm">
      <div>Name: Omkar</div>
      <div>Email: itsofficialomkar@gmail.com</div>
      <div>Role: Super Admin</div>
    </div>
  );

  return (
    <Fragment>
      <div className="p-4 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        <Panel title="Details">{Details}</Panel>
        <Panel title="Hospitals">
          <div className="space-y-1 text-sm">
            <div>Total Hospitals: {allUsers ? allUsers.filter((user) => user.role === 1).length : 0}</div>
          </div>
        </Panel>
        <Panel title="Patients">
          <div className="space-y-1 text-sm">
            <div>Total Patients: {allUsers ? allUsers.filter((user) => user.role === 0).length : 0}</div>
          </div>
        </Panel>
        <Panel title="Organ Categories">
          <div className="space-y-1 text-sm">
            <div>Total Categories: {allCategories ? allCategories.length : 0}</div>
          </div>
        </Panel>
        <Panel title="Organs">
          <div className="space-y-1 text-sm">
            <div>Total Organs: {allProducts ? allProducts.length : 0}</div>
          </div>
        </Panel>
        <Panel title="Analytics">
          <div className="space-y-1 text-sm">
            <div>Total Orders: {allOrders ? allOrders.length : 0}</div>
            <div>Total Revenue: {allOrders ? allOrders.reduce((acc, curr) => acc + curr.amount, 0) : 0}</div>
          </div>
        </Panel>
      </div>
    </Fragment>
  );
};

const SuperAdminPage = () => {
  return (
    <Fragment>
      <AdminLayout children={<SuperAdminDashboard />} />
    </Fragment>
  );
};

export default SuperAdminPage;
